#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") != "Bash":
        return 0

    cmd = (ev.get("tool_input") or {}).get("command", "")
    cmd_stripped = cmd.strip()

    # Block bare `pnpm test` (interactive watcher); allow `pnpm test:ci` and variants
    if cmd_stripped == "pnpm test":
        print(
            "Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and will timeout.",
            file=sys.stderr
        )
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

