#!/usr/bin/env python3
import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Edit", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}
    if "tree" not in inp.get("file_path", "").lower():
        return 0

    if tool == "Edit":
        old_code = inp.get("old_string", "")
        new_code = inp.get("new_string", "")
    else:
        edits = inp.get("edits") or []
        old_code = "\n".join(e.get("old_string", "") for e in edits)
        new_code = "\n".join(e.get("new_string", "") for e in edits)

    old_recursive = bool(re.search(r"def\s+(\w+)\s*\([^)]*\):.*?\1\s*\(", old_code, re.DOTALL))
    new_recursive = bool(re.search(r"def\s+(\w+)\s*\([^)]*\):.*?\1\s*\(", new_code, re.DOTALL))

    if new_recursive and not old_recursive:
        print(
            "Recursive tree functions will hit Python's ~1000-node recursion limit.\n"
            "Keep the iterative stack/worklist approach.",
            file=sys.stderr
        )
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

