#!/usr/bin/env python3
"""After Edit/MultiEdit to a Python file, run ruff format to auto-fix style."""
import json, subprocess, sys, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    if not file_path.endswith(".py"):
        return 0

    if not os.path.isfile(file_path):
        return 0

    try:
        result = subprocess.run(
            ["ruff", "format", file_path],
            capture_output=True,
            text=True,
            timeout=10,
        )
        if result.stdout:
            print(f"Auto-formatted {file_path}", file=sys.stderr)
            print(result.stdout, file=sys.stderr)
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit, if an exported identifier is touched, grep for all references."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}

    # Collect all edited strings
    if inp.get("old_string") is not None:
        edits = [{"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}]
    else:
        edits = inp.get("edits") or []

    # Extract exported identifier names
    names = set()
    for e in edits:
        for s in (e.get("old_string", ""), e.get("new_string", "")):
            m = EXPORT_DEF.search(s)
            if m:
                names.add(m.group(1))

    if not names:
        return 0

    cwd = ev.get("cwd", ".")
    found_refs = False

    for name in sorted(names):
        try:
            r = subprocess.run(
                ["grep", "-rn", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", "--include=*.py",
                 r"\b" + name + r"\b", cwd],
                capture_output=True, text=True, timeout=5, cwd=cwd
            )

            hits = [l.strip() for l in r.stdout.splitlines() if l.strip()]
            if hits:
                found_refs = True
                print(f"Export '{name}' edited. Found {len(hits)} reference(s):", file=sys.stderr)
                for h in hits[:20]:
                    print(f"  {h}", file=sys.stderr)
                if len(hits) > 20:
                    print(f"  ... and {len(hits) - 20} more", file=sys.stderr)
        except Exception:
            pass

    if found_refs:
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())
